    def parse_saml_response(self, saml_response_xml):
        root = ET.fromstring(saml_response_xml)
        ns = {'saml': 'urn:oasis:names:tc:SAML:2.0:assertion'}

        name_id = root.find('.//saml:Subject/saml:NameID', ns)
        if name_id is None:
            return None

        attributes = {}
        for attribute in root.findall('.//saml:Attribute', ns):
            attr_name = attribute.get('Name')
            attr_value = attribute.find('saml:AttributeValue', ns).text
            attributes[attr_name] = attr_value

        attributes['NameID'] = name_id.text
        return attributes

